import{_ as o,o as a,c as t,ag as s}from"./chunks/framework.BKDXG6j6.js";const m=JSON.parse('{"title":"Jetpack Compose","description":"","frontmatter":{},"headers":[],"relativePath":"ui/jetpack-compose.md","filePath":"ui/jetpack-compose.md","lastUpdated":null}'),i={name:"ui/jetpack-compose.md"};function n(r,e,l,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="jetpack-compose" tabindex="-1">Jetpack Compose <a class="header-anchor" href="#jetpack-compose" aria-label="Permalink to &quot;Jetpack Compose&quot;">​</a></h1><p>Jetpack Compose is Android’s modern declarative UI toolkit. It drastically reduces boilerplate and speeds up UI development by describing <em>what</em> the UI should look like for a given state, rather than <em>how</em> to mutate it over time.</p><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><h3 id="_1-declarative-paradigm" tabindex="-1">1. Declarative Paradigm <a class="header-anchor" href="#_1-declarative-paradigm" aria-label="Permalink to &quot;1. Declarative Paradigm&quot;">​</a></h3><p>Instead of manually updating UI widgets (e.g., <code>textView.setText(data)</code>), your Composables observe state. When the state changes, Compose automatically re-executes (recomposes) the specific functions that read that state.</p><h3 id="_2-basic-composables" tabindex="-1">2. Basic Composables <a class="header-anchor" href="#_2-basic-composables" aria-label="Permalink to &quot;2. Basic Composables&quot;">​</a></h3><ul><li><strong><code>Text</code></strong>: Displays text.</li><li><strong><code>Image</code></strong> / <strong><code>Icon</code></strong>: Displays graphics.</li><li><strong><code>Button</code></strong>: Handles clicks.</li><li><strong><code>TextField</code></strong>: Input field.</li></ul><h3 id="_3-layouts" tabindex="-1">3. Layouts <a class="header-anchor" href="#_3-layouts" aria-label="Permalink to &quot;3. Layouts&quot;">​</a></h3><ul><li><strong><code>Column</code></strong>: Arranges elements vertically (<code>LinearLayout(vertical)</code> equivalent).</li><li><strong><code>Row</code></strong>: Arranges elements horizontally (<code>LinearLayout(horizontal)</code> equivalent).</li><li><strong><code>Box</code></strong>: Stacks elements on top of each other (<code>FrameLayout</code> equivalent).</li><li><strong><code>LazyColumn</code></strong> / <strong><code>LazyRow</code></strong>: The Compose equivalent of <code>RecyclerView</code>. Emits only the visible items.</li></ul><h3 id="_4-modifiers" tabindex="-1">4. Modifiers <a class="header-anchor" href="#_4-modifiers" aria-label="Permalink to &quot;4. Modifiers&quot;">​</a></h3><p>Used to decorate or configure a composable (padding, background, click listeners, size). <em>Important:</em> The order of Modifiers matters! <code>Modifier.padding(16.dp).background(Color.Red)</code> looks different from <code>Modifier.background(Color.Red).padding(16.dp)</code>.</p><h3 id="_5-state-management" tabindex="-1">5. State Management <a class="header-anchor" href="#_5-state-management" aria-label="Permalink to &quot;5. State Management&quot;">​</a></h3><ul><li><code>remember</code>: Caches an object across recompositions.</li><li><code>mutableStateOf</code>: An observable state holder. Changes to its value trigger recompositions.</li></ul><div class="language-kotlin vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">kotlin</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">by</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> remember</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mutableStateOf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) }</span></span></code></pre></div><ul><li><strong>State Hoisting</strong>: A pattern where you move state up to a parent composable to make the child stateless and reusable.</li></ul><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ol><li><strong>Unidirectional Data Flow (UDF)</strong>: Events flow up, State flows down. Composables pass events to the ViewModel, the ViewModel updates the StateFlow, and the Composable recomposes based on the new State.</li><li><strong>Stable Types</strong>: Ensure objects passed to Composables are <code>@Stable</code> or <code>@Immutable</code> (like Data Classes with <code>val</code> properties). If Compose isn&#39;t sure an object changed, it recommits unnecessarily.</li><li><strong>Avoid heavy computations in Composable functions</strong>: They can execute hundreds of times per second (e.g., during animations).</li></ol><h2 id="interview-questions" tabindex="-1">Interview Questions <a class="header-anchor" href="#interview-questions" aria-label="Permalink to &quot;Interview Questions&quot;">​</a></h2><p><strong>Q: What is Recomposition?</strong><em>Answer:</em> Recomposition is the process of calling your composable functions again when their inputs (state) change. Compose intelligently tracks which data belongs to which composable and only updates the parts of the UI whose data changed, skipping the rest.</p><p><strong>Q: How do you perform a side effect in Compose without running it on every recomposition?</strong><em>Answer:</em> You use Side-Effect APIs like <code>LaunchedEffect</code> (runs a suspending function based on a key), <code>DisposableEffect</code> (runs when a key changes and provides a cleanup block), or <code>SideEffect</code> (runs after every successful recomposition).</p>',20)])])}const u=o(i,[["render",n]]);export{m as __pageData,u as default};
